using Moq;
using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsException<ArgumentNullException>(() => new Payments.PaymentGateway(null!));
        Assert.AreEqual("provider", ex.ParamName);
    }

    [TestMethod]
    public void Constructor_ValidProvider_DoesNotThrow()
    {
        var provider = new Mock<IPaymentProvider>();
        var gateway = new Payments.PaymentGateway(provider.Object);
        Assert.IsNotNull(gateway);
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(_mockProvider.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        var ex = await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
        Assert.AreEqual("cardToken", ex.ParamName);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        var ex = await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
        Assert.AreEqual("amount", ex.ParamName);
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMax_ThrowsArgumentOutOfRangeException()
    {
        var ex = await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", Payments.PaymentGateway.MaxChargeAmount + 0.01m));
        Assert.AreEqual("amount", ex.ParamName);
    }

    [TestMethod]
    public async Task ChargeAsync_AmountAtMax_Succeeds()
    {
        var expected = new ChargeResult("ch_max", true);
        _mockProvider
            .Setup(p => p.ChargeAsync("tok_valid", Payments.PaymentGateway.MaxChargeAmount))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_valid", Payments.PaymentGateway.MaxChargeAmount);

        Assert.AreEqual(expected, result);
    }

    // --- Happy-path tests ---

    [TestMethod]
    public async Task ChargeAsync_ValidRequest_ReturnsSuccessResult()
    {
        var expected = new ChargeResult("ch_123", true);
        _mockProvider
            .Setup(p => p.ChargeAsync("tok_abc", 49.99m))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_abc", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderReturnsFailure_ReturnsFailureResult()
    {
        var expected = new ChargeResult("ch_fail", false);
        _mockProvider
            .Setup(p => p.ChargeAsync("tok_bad", 10m))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_bad", 10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_DelegatesToProvider_WithCorrectArguments()
    {
        _mockProvider
            .Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ReturnsAsync(new ChargeResult("ch_1", true));

        await _gateway.ChargeAsync("tok_xyz", 100m);

        _mockProvider.Verify(p => p.ChargeAsync("tok_xyz", 100m), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _mockProvider
            .Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new InvalidOperationException("Provider unavailable"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_abc", 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_SmallAmount_Succeeds()
    {
        var expected = new ChargeResult("ch_penny", true);
        _mockProvider
            .Setup(p => p.ChargeAsync("tok_valid", 0.01m))
            .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_penny", result.ChargeId);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Mock<IPaymentProvider> _mockProvider = null!;
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _mockProvider = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(_mockProvider.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        var ex = await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
        Assert.AreEqual("chargeId", ex.ParamName);
    }

    // --- Happy-path tests ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        var expected = new RefundResult("re_456", true);
        _mockProvider
            .Setup(p => p.RefundAsync("ch_123"))
            .ReturnsAsync(expected);

        var result = await _gateway.RefundAsync("ch_123");

        Assert.IsTrue(result.Success);
        Assert.AreEqual("re_456", result.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderReturnsFailure_ReturnsFailureResult()
    {
        var expected = new RefundResult("re_fail", false);
        _mockProvider
            .Setup(p => p.RefundAsync("ch_nonexistent"))
            .ReturnsAsync(expected);

        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_DelegatesToProvider_WithCorrectArguments()
    {
        _mockProvider
            .Setup(p => p.RefundAsync(It.IsAny<string>()))
            .ReturnsAsync(new RefundResult("re_1", true));

        await _gateway.RefundAsync("ch_target");

        _mockProvider.Verify(p => p.RefundAsync("ch_target"), Times.Once);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderThrows_ExceptionPropagates()
    {
        _mockProvider
            .Setup(p => p.RefundAsync(It.IsAny<string>()))
            .ThrowsAsync(new InvalidOperationException("Provider unavailable"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.RefundAsync("ch_123"));
    }
}

[TestClass]
public class ProcessWebhookTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        var provider = new Mock<IPaymentProvider>();
        _gateway = new Payments.PaymentGateway(provider.Object);
    }

    // --- Validation tests ---

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_InvalidEventType_ThrowsArgumentException(string? eventType)
    {
        var ex = Assert.ThrowsException<ArgumentException>(
            () => _gateway.ProcessWebhook(eventType!, "{}"));
        Assert.AreEqual("eventType", ex.ParamName);
    }

    [TestMethod]
    [DataRow(null)]
